const xml = $input.first().json.data;

// HTML 응답 체크
if (xml.includes('<!doctype html') || xml.includes('<html')) {
  throw new Error('RSS XML이 아닌 HTML 페이지가 반환됨. URL을 확인하세요.');
}

// <item> 블록 추출
const itemRegex = /<item[\s\S]*?<\/item>/gi;
const items = [];
let match;
let count = 0;

const getTag = (block, tag) => {
  const m = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`, 'i'));
  if (!m) return '';
  return m[1]
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
    .replace(/<[^>]*>/g, '')
    .trim();
};

while ((match = itemRegex.exec(xml)) !== null && count < 5) {
  const block = match[0];
  items.push({
    json: {
      rank: count + 1,
      title: getTag(block, 'title'),
      link: getTag(block, 'link') || getTag(block, 'guid'),
      description: getTag(block, 'description'),
      pubDate: getTag(block, 'pubDate'),
      category: getTag(block, 'category')
    }
  });
  count++;
}

if (items.length === 0) {
  throw new Error('파싱된 뉴스 아이템이 없음. XML 구조를 확인하세요.');
}

return items;

const items = $input.all();

let message = '📰 주요 뉴스 TOP 5\n';
message += '━━━━━━━━━━━━━━━━━━━━\n';

for (const item of items) {
  const { rank, title, link, pubDate } = item.json;
  message += `\n${rank}위. ${title}\n🔗 ${link}\n🕐 ${pubDate}\n`;
}

return [{ json: { message, count: items.length, generatedAt: new Date().toISOString() } }];
